ogy, AppImages.numerology),      (AppStrings.homePalmistry, AppImages.palmistry),      (AppStrings.homeRitualHealing, AppImages.ritualHealing),      (AppStrings.homeVastu, AppImages.vastu),    ];    return Container(      width: double.infinity,      padding: const EdgeInsets.symmetric(horizontal: 2),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          const _SectionTitle(            title: AppStrings.homeOurServices,            icon: Icons.auto_awesome,          ),          const SizedBox(height: 10),          GridView.builder(            padding: EdgeInsets.zero,            itemCount: items.length,            shrinkWrap: true,            physics: const NeverScrollableScrollPhysics(),            gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(              crossAxisCount: 2,              mainAxisSpacing: 12,              crossAxisSpacing: 12,              childAspectRatio: 1.18,            ),            itemBuilder: (context, index) {              return _ServiceTile(                title: items[index].$1,                imagePath: items[index].$2,              );            },          ),        ],      ),    );  }}class _FeaturedAstrologersSection extends StatelessWidget {  const _FeaturedAstrologersSection();  @override  Widget build(BuildContext context) {    return Column(      children: const [        Padding(          padding: EdgeInsets.symmetric(horizontal: 2),          child: Align(            alignment: Alignment.centerLeft,            child: _SectionTitle(              title: AppStrings.homeFeaturedAstrologers,              icon: Icons.star_outline_rounded,            ),          ),        ),        SizedBox(height: 10),        _AstrologerCard(),        SizedBox(height: 10),        _AstrologerCard(),        SizedBox(height: 10),        _AstrologerCard(),      ],    );  }}class _TrendingServicesSection extends StatelessWidge