olors.homeTrendingPinkEnd],        ),        borderRadius: BorderRadius.circular(24),        boxShadow: const [          BoxShadow(            color: AppColors.homeServiceShadow,            blurRadius: 16,            offset: Offset(0, 8),          ),        ],      ),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          if (imagePath != null)            Image.asset(              imagePath!,              width: 40,              height: 40,              fit: BoxFit.cover,            )          else            Container(              width: 40,              height: 40,              decoration: BoxDecoration(                color: AppColors.whiteColor.withValues(alpha: darkText ? 0.32 : 0.18),                borderRadius: BorderRadius.circular(8),              ),            ),          const SizedBox(height: 18),          Text(            title,            style: TextStyle(              color: textColor,              fontSize: 16,              fontWeight: FontWeight.w500,              height: 1.1,            ),          ),          const SizedBox(height: 8),          Text(            subtitle,            style: TextStyle(              color: subtitleColor,              fontSize: 14,              fontWeight: FontWeight.w500,              height: 1.25,            ),          ),        ],      ),    );  }}class _AvatarPlaceholder extends StatelessWidget {  const _AvatarPlaceholder({required this.size});  final double size;  @override  Widget build(BuildContext context) {    return Container(      width: size,      height: size,      decoration: BoxDecoration(        shape: BoxShape.circle,        color: AppColors.homePlaceholderBackground,        border: Border.all(color: AppColors.homePlaceholderBorder),      ),      alignment: Alignment.center,      child: const Text(        AppStrings.imagePlaceholder,        textAlign: TextAlign.center,        style: TextStyle(          color: AppColors.homePlaceholderText,          fontSize: 8,          fontWeight: FontWeight.w700,        ),      ),    );  }}class _NotificationPlaceholder extends StatelessWidget {  const _NotificationPlaceholder();  @override  Widget build(BuildContext context) {    return Container(      width: 54,      height: 54,      decoration: BoxDecoration(        shape: BoxShape.circle,        border: Border.all(color: AppColors.homeNotificationBorder, width: 1.6),        color: AppColors.homeNotificationBackground,      ),      child: Stack(        alignment: Alignment.center,        children: const [          Icon(            Icons.notifications_none_rounded,            size: 28,            color: AppColors.whiteColor,          ),          Positioned(            top: 13,            right: 13,            child: DecoratedBox(              decoration: BoxDecoration(                color: AppColors.homeNotificationBadge,                shape: BoxShape.circle,              ),              child: SizedBox(width: 12, height: 12),            ),          ),        ],      ),    );  }}